12	// LivenessRecord is the worker-side sidecar written under
13	// .ddx/workers/<worker-id>/status.json to mirror live progress of a
14	// long-running ddx work / ddx try attempt without rewriting beads.jsonl.
15	//
16	// The bead tracker remains the durable claim marker; this sidecar carries
17	// the high-frequency liveness signal so operators can answer "is the worker
18	// alive and what is it doing?" without inflating tracker churn.
19	type LivenessRecord struct {
20		WorkerID       string    `json:"worker_id"`
21		ProjectRoot    string    `json:"project_root,omitempty"`
22		CurrentBead    string    `json:"current_bead,omitempty"`
23		AttemptID      string    `json:"attempt_id,omitempty"`
24		Phase          string    `json:"phase,omitempty"`
25		Route          string    `json:"route,omitempty"`
26		Harness        string    `json:"harness,omitempty"`
27		Model          string    `json:"model,omitempty"`
28		Profile        string    `json:"profile,omitempty"`
29		PID            int       `json:"pid,omitempty"`
30		ChildPID       int       `json:"child_pid,omitempty"`
31		StartedAt      time.Time `json:"started_at,omitempty"`
32		LastActivityAt time.Time `json:"last_activity_at"`
33	}
34	
35	// LivenessTTL is the freshness window for treating a worker sidecar as
36	// "active". Defaults to 3× the bead tracker heartbeat interval (which is
37	// 30s) so a sidecar that has not been touched in ~90s is treated as stale.
38	var LivenessTTL = 90 * time.Second
39	
40	// LivenessDir returns the worker sidecar directory for a project.
41	func LivenessDir(projectRoot string) string {
42		return filepath.Join(projectRoot, ".ddx", "workers")
43	}
44	
45	// LivenessPath returns the status.json path for a worker under projectRoot.
46	func LivenessPath(projectRoot, workerID string) string {
47		return filepath.Join(LivenessDir(projectRoot), workerID, "status.json")
48	}
49	
50	// WriteLiveness writes rec to .ddx/workers/<workerID>/status.json using a
51	// tmp-then-rename so concurrent readers never see a half-written file.
52	func WriteLiveness(projectRoot, workerID string, rec LivenessRecord) error {
53		if projectRoot == "" || workerID == "" {
54			return fmt.Errorf("workerstatus: project root and worker id required")
55		}
56		dir := filepath.Join(LivenessDir(projectRoot), workerID)
57		if err := os.MkdirAll(dir, 0o755); err != nil {
58			return fmt.Errorf("workerstatus: mkdir worker dir: %w", err)
59		}
60		data, err := json.MarshalIndent(rec, "", "  ")
61		if err != nil {
62			return fmt.Errorf("workerstatus: marshal liveness: %w", err)
63		}
64		data = append(data, '\n')
65		final := filepath.Join(dir, "status.json")
66		tmp, err := os.CreateTemp(dir, "status-*.tmp")
67		if err != nil {
68			return fmt.Errorf("workerstatus: create tmp: %w", err)
69		}
70		tmpName := tmp.Name()
71		if _, err := tmp.Write(data); err != nil {
72			_ = tmp.Close()
73			_ = os.Remove(tmpName)
74			return fmt.Errorf("workerstatus: write tmp: %w", err)
75		}
76		if err := tmp.Close(); err != nil {
77			_ = os.Remove(tmpName)
78			return fmt.Errorf("workerstatus: close tmp: %w", err)
79		}
80		if err := os.Rename(tmpName, final); err != nil {
81			_ = os.Remove(tmpName)
82			return fmt.Errorf("workerstatus: rename: %w", err)
83		}
84		return nil
85	}
86	
87	// ReadLiveness reads the sidecar for workerID under projectRoot.
88	func ReadLiveness(projectRoot, workerID string) (LivenessRecord, error) {
89		var rec LivenessRecord
90		data, err := os.ReadFile(LivenessPath(projectRoot, workerID))
91		if err != nil {
92			return rec, err
93		}
94		if err := json.Unmarshal(data, &rec); err != nil {
95			return rec, fmt.Errorf("workerstatus: parse liveness: %w", err)
96		}
97		return rec, nil
98	}
99	
100	// ListLiveness reads every status.json sidecar under projectRoot's worker
101	// directory. Malformed sidecars are skipped silently — the sidecar is
102	// best-effort observability, not authoritative state.
103	func ListLiveness(projectRoot string) ([]LivenessRecord, error) {
104		dir := LivenessDir(projectRoot)
105		entries, err := os.ReadDir(dir)
106		if err != nil {
107			if os.IsNotExist(err) {
108				return nil, nil
109			}
110			return nil, err
111		}
112		var out []LivenessRecord
113		for _, entry := range entries {
114			if !entry.IsDir() {
115				continue
116			}
117			rec, err := ReadLiveness(projectRoot, entry.Name())
118			if err != nil {
119				continue
120			}
121			out = append(out, rec)
122		}
123		sort.Slice(out, func(i, j int) bool {
124			return out[i].LastActivityAt.After(out[j].LastActivityAt)
125		})
126		return out, nil
127	}
128	
129	// IsFresh reports whether rec.LastActivityAt is within LivenessTTL of now.
130	func (r LivenessRecord) IsFresh(now time.Time) bool {
131		if r.LastActivityAt.IsZero() {
132			return false
133		}
134		return now.Sub(r.LastActivityAt) <= LivenessTTL
135	}
