20	func TestWithHeartbeat_TickerFiredBeforeReturn(t *testing.T) {
21		store := &stubHeartbeatStore{}
22		tickCh := make(chan time.Time, 1)
23		tickCh <- time.Now()
24	
25		_, err := withHeartbeatCh(context.Background(), "bead-1", tickCh, store, nil, func() (struct{}, error) {
26			time.Sleep(10 * time.Millisecond)
27			return struct{}{}, nil
28		})
29	
30		if err != nil {
31			t.Fatalf("unexpected error: %v", err)
32		}
33		if store.count.Load() < 1 {
34			t.Errorf("expected Heartbeat called at least once, got %d", store.count.Load())
35		}
36	}
