38	func TestWithHeartbeat_CancelPropagates(t *testing.T) {
39		store := &stubHeartbeatStore{}
40		ctx, cancel := context.WithCancel(context.Background())
41		tickCh := make(chan time.Time) // unbuffered; no ticks will be sent
42	
43		done := make(chan struct{})
44		go func() {
45			defer close(done)
46			_, _ = withHeartbeatCh(ctx, "bead-1", tickCh, store, nil, func() (struct{}, error) {
47				cancel()
48				return struct{}{}, errors.New("fn error")
49			})
50		}()
51	
52		select {
53		case <-done:
54		case <-time.After(1 * time.Second):
55			t.Fatal("withHeartbeatCh did not return after context cancellation")
56		}
57	}
