37	func parseExecuteLoopSpec(cmd *cobra.Command, treatPassthroughAsOpaque bool) (executeloop.ExecuteLoopSpec, executeloop.DispatchOptions, error) {
38		projectRoot, _ := cmd.Flags().GetString("project")
39		fromRev, _ := cmd.Flags().GetString("from")
40		harness, _ := cmd.Flags().GetString("harness")
41		model, _ := cmd.Flags().GetString("model")
42		profile, _ := cmd.Flags().GetString("profile")
43		provider, _ := cmd.Flags().GetString("provider")
44		effort, _ := cmd.Flags().GetString("effort")
45		once, _ := cmd.Flags().GetBool("once")
46		watch, _ := cmd.Flags().GetBool("watch")
47		rawIdleInterval, _ := cmd.Flags().GetDuration("idle-interval")
48		asJSON, _ := cmd.Flags().GetBool("json")
49		dispatchJSON := ""
50		if asJSON {
51			dispatchJSON = "true"
52		}
53		local, _ := cmd.Flags().GetBool("local")
54		noReview, _ := cmd.Flags().GetBool("no-review")
55		noReviewAck, _ := cmd.Flags().GetBool("no-review-i-know-what-im-doing")
56		reviewHarness, _ := cmd.Flags().GetString("review-harness")
57		reviewModel, _ := cmd.Flags().GetString("review-model")
58		maxCostUSD, _ := cmd.Flags().GetFloat64("max-cost")
59		maxBeadCostUSD, _ := cmd.Flags().GetFloat64("max-bead-cost")
60		maxRecoveryCostUSD, _ := cmd.Flags().GetFloat64("max-recovery-cost")
61		preClaimTimeout, _ := cmd.Flags().GetDuration("preclaim-timeout")
62		requestTimeout, _ := cmd.Flags().GetDuration("request-timeout")
63		rateLimitMaxWait, _ := cmd.Flags().GetDuration("rate-limit-max-wait")
64		minPower, _ := cmd.Flags().GetInt("min-power")
65		maxPower, _ := cmd.Flags().GetInt("max-power")
66	
67		if noReview && !noReviewAck {
68			return executeloop.ExecuteLoopSpec{}, executeloop.DispatchOptions{}, fmt.Errorf("--no-review requires --no-review-i-know-what-im-doing (break-glass acknowledgement)")
69		}
70		if once && watch {
71			return executeloop.ExecuteLoopSpec{}, executeloop.DispatchOptions{}, fmt.Errorf("--once and --watch are mutually exclusive")
72		}
73		if !watch && cmd.Flags().Changed("idle-interval") {
74			return executeloop.ExecuteLoopSpec{}, executeloop.DispatchOptions{}, fmt.Errorf("--idle-interval only applies in watch mode; pass --watch")
75		}
76	
77		mode := executeloop.ModeDrain
78		var idleInterval executeloop.Duration
79		if once {
80			mode = executeloop.ModeOnce
81		} else if watch {
82			mode = executeloop.ModeWatch
83			idleInterval = executeloop.Duration{Duration: rawIdleInterval}
84		}
85	
86		spec := executeloop.ExecuteLoopSpec{
87			ProjectRoot:        projectRoot,
88			Harness:            harness,
89			Model:              model,
90			Profile:            profile,
91			Provider:           provider,
92			Effort:             effort,
93			Mode:               mode,
94			IdleInterval:       idleInterval,
95			NoReview:           noReview,
96			ReviewHarness:      reviewHarness,
97			ReviewModel:        reviewModel,
98			OpaquePassthrough:  treatPassthroughAsOpaque,
99			MaxCostUSD:         maxCostUSD,
100			MaxBeadCostUSD:     maxBeadCostUSD,
101			MaxRecoveryCostUSD: maxRecoveryCostUSD,
102			PreClaimTimeout:    executeloop.Duration{Duration: preClaimTimeout},
103			RequestTimeout:     executeloop.Duration{Duration: requestTimeout},
104			RateLimitMaxWait:   executeloop.Duration{Duration: rateLimitMaxWait},
105			MinPower:           minPower,
106			MaxPower:           maxPower,
107			FromRev:            fromRev,
108		}
109		spec.ApplyDefaults()
110		if err := spec.Validate(); err != nil {
111			return executeloop.ExecuteLoopSpec{}, executeloop.DispatchOptions{}, err
112		}
113	
114		return spec, executeloop.DispatchOptions{Local: local, JSON: dispatchJSON}, nil
115	}
